enum Status {
  Pending  = "PENDING",
  Active   = "ACTIVE",
  Archived = "ARCHIVED",
}

function describe(s: Status): string {
  switch (s) {
    case Status.Pending:  return "Waiting for review";
    case Status.Active:   return "Currently active";
    case Status.Archived: return "No longer active";
  }
}

console.log(Status.Active);
console.log(describe(Status.Pending));
console.log(describe(Status.Archived));

